"use strict";parserFactory.register("crushnovelpo.blog",()=>new CrushnovelParser);class CrushnovelParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=this.getNumberOfPages(e),t=e.baseURI.replace("/novel/","/read/")+"/chapter-";if(50<r){let e=[];for(let l=1;l<r;++l)e.push({title:"Chapter "+l,sourceUrl:t+l});return e}return[...e.querySelectorAll("#chapters a")].map(e=>({title:e.querySelector("h4").textContent,sourceUrl:e.href}))}getNumberOfPages(e){let r=[...e.querySelectorAll("script")].map(e=>e.textContent).filter(e=>e.includes("numberOfPages"))[0];return r?JSON.parse(r).numberOfPages:0}findContent(e){return e.querySelector(".chapter-content")}extractTitleImpl(e){return e.querySelector("main h1")}findChapterTitle(e){return e.querySelector(".container h2")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".book-cover")}preprocessRawDom(e){let r=this.findContent(e),t=[...r.querySelectorAll(".prose")];r.replaceChildren(),t.forEach(e=>r.appendChild(e))}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#story-full")]}}